function initBurger(){const e=document.getElementById("burgerBtn"),t=document.getElementById("sidebarNav"),o=document.getElementById("logoutBtn");e&&t&&e.addEventListener("click",()=>{const i=e.classList.contains("sidebar__burger--active");e.classList.toggle("sidebar__burger--active"),e.setAttribute("aria-expanded",!i),t.classList.toggle("sidebar__nav--open"),o&&o.classList.toggle("sidebar__logout--open")})}function showNotification(e,t="success"){const o=document.querySelector(".notification");o&&o.remove();const i=document.createElement("div");i.className=`notification notification--${t}`,i.textContent=e,document.body.appendChild(i),requestAnimationFrame(()=>{i.classList.add("notification--visible")}),setTimeout(()=>{i.classList.remove("notification--visible"),setTimeout(()=>i.remove(),300)},3e3)}function initLogout(){const e=document.getElementById("logoutBtn");e&&e.addEventListener("click",()=>{window.location.href="login.html"})}function initModals(){document.addEventListener("click",e=>{e.target.classList.contains("modal-overlay")&&e.target.classList.remove("modal-overlay--active")}),document.addEventListener("keydown",e=>{if("Escape"===e.key){document.querySelectorAll(".modal-overlay--active").forEach(e=>e.classList.remove("modal-overlay--active"))}})}document.addEventListener("DOMContentLoaded",()=>{initBurger(),initLogout(),initModals()});